async (params, browser) => {
  // Open user profile
  await browser.open(`https://news.ycombinator.com/user?id=${params.username}`)

  // Wait for profile to load
  await browser.waitForSelector('table', 15000)

  // Let page settle
  await browser.wait(1500)

  // Extract user profile
  const user_profile = await browser.evaluate(`const usernameFromUrl = new URL(window.location.href).searchParams.get('id') || ''; const rows = document.querySelectorAll('table table tr'); let username = ''; let karma = ''; let about = ''; let created = ''; for (const row of rows) { const label = row.querySelector('td:first-child'); const value = row.querySelector('td:nth-child(2)'); if (!label || !value) continue; const labelText = label.textContent.trim().toLowerCase(); if (labelText.includes('user')) username = value.textContent.trim(); else if (labelText.includes('karma')) karma = value.textContent.trim(); else if (labelText.includes('about')) about = value.textContent.trim().slice(0, 1000); else if (labelText.includes('created')) created = value.textContent.trim(); } return { username: username || usernameFromUrl, karma: karma, about: about, created: created, profile_url: window.location.href }`)

  // Open user submissions
  await browser.open(`https://news.ycombinator.com/submitted?id=${params.username}`)

  // Wait for submissions
  await browser.waitForSelector('.athing', 15000)

  // Let submissions load
  await browser.wait(1500)

  // Extract recent submissions
  const user_submissions = await browser.evaluate(`const usernameFromUrl = new URL(window.location.href).searchParams.get('id') || ''; const submissions = []; const storyRows = document.querySelectorAll('.athing'); for (let i = 0; i < Math.min(storyRows.length, 15); i++) { const row = storyRows[i]; const subtext = row.nextElementSibling; const titleEl = row.querySelector('.titleline > a'); const scoreEl = subtext ? subtext.querySelector('.score') : null; const ageEl = subtext ? subtext.querySelector('.age a') : null; let commentCount = '0'; if (subtext) { const links = subtext.querySelectorAll('a'); for (const link of links) { const text = link.textContent.trim(); if (text.includes('comment')) { commentCount = text.split('\u00a0')[0] || text.split(' ')[0]; break; } } } submissions.push({ title: titleEl ? titleEl.textContent.trim() : '', url: titleEl ? titleEl.href : '', score: scoreEl ? scoreEl.textContent.trim() : '0 points', comment_count: commentCount, age: ageEl ? ageEl.textContent.trim() : '' }); } return { username: usernameFromUrl, submission_count: submissions.length, submissions: submissions }`)

  return user_submissions
}
